function Comment({ comment }) {
  return <div className="comment" dangerouslySetInnerHTML={{ __html: comment.body }} />;
}

import DOMPurify from 'dompurify';
function Comment({ comment }) {
  const clean = DOMPurify.sanitize(comment.body, { USE_PROFILES: { html: true } });
  return <div className="comment" dangerouslySetInnerHTML={{ __html: clean }} />;
}

function compute(req, res) {
  const expr = req.query.expr;
  const result = eval(expr);
  res.json({ result });
}

import { evaluate } from 'mathjs';
function compute(req, res) {
  const expr = String(req.query.expr || '');
  if (!/^[-+*/().\d\s]+$/.test(expr)) {
    return res.status(400).json({ error: 'invalid expression' });
  }
  const result = evaluate(expr);
  res.json({ result });
}
